/* 环形缓冲区 ADT 接口定义（伪代码） */

typedef struct {
    volatile uint16_t head;
    volatile uint16_t tail;
    uint16_t size;
    uint16_t mask;
    uint8_t overflow;
    uint8_t data[];
} ring_buffer_t;

/* 公开接口 */
ring_buffer_t *ringbuf_create(uint16_t buf_size);
void ringbuf_destroy(ring_buffer_t *rb);
int ringbuf_push(ring_buffer_t *rb, uint8_t byte);
int ringbuf_pop(ring_buffer_t *rb, uint8_t *out);
uint16_t ringbuf_count(ring_buffer_t *rb);
void ringbuf_clear(ring_buffer_t *rb);

/* dma_ringbuf_isr.c - DMA 传输完成回调中的 head 更新 */
#include <stm32l4xx_hal.h>

/* 缓冲区参数 */
#define RING_SIZE 512
#define RING_MASK (RING_SIZE - 1)

/* 环形缓冲区——ISR 写 head，任务读 head 写 tail */
static volatile uint16_t rx_head = 0;
static volatile uint16_t rx_tail = 0;
static volatile uint8_t overflow_flag = 0;
static uint8_t rx_buffer[RING_SIZE]
    __attribute__((aligned(8)));
static uint16_t prev_head = 0;

/* DMA 传输完成回调——由 HAL 库自动调用 */
void HAL_UART_RxCpltCallback(UART_HandleTypeDef *huart) {
    /* 第 1 步：__DSB 确保 DMA 写入的内存可见 */
    __DSB();

    /* 第 2 步：更新 head 指针（步进式，不读 CNDTR）*/
    uint16_t new_head = (rx_head + 1) & RING_MASK;

    /* 第 3 步：溢出检测——transferred 回绕超一半 */
    if ((new_head - prev_head) & RING_MASK > RING_SIZE / 2) {
        overflow_flag = 1;
    }
    prev_head = new_head;

    /* 第 4 步：提交新 DMA 传输（Circular 模式可省）*/
    /* HAL_UART_Receive_DMA(huart, rx_buffer, RING_SIZE); */

    /* 第 5 步：更新 head——必须在最后，确保前面写入可见 */
    __DSB();
    rx_head = new_head;
}

/* 陷阱 5 修复：快照模式——避免 while(avail) 死锁 */
void process_ring_buffer(void) {
    /* 第 1 步：读 head/tail 到局部变量（快照）*/
    uint16_t head_snap = rx_head;
    uint16_t tail_snap = rx_tail;

    /* 第 2 步：用快照值计算可用字节数 */
    uint16_t avail;
    if (head_snap >= tail_snap) {
        avail = head_snap - tail_snap;
    } else {
        avail = RING_SIZE - tail_snap + head_snap;
    }

    /* 第 3 步：用快照值循环读取——ISR 不会干扰 */
    for (uint16_t i = 0; i < avail; i++) {
        uint8_t byte = rx_buffer[tail_snap];
        tail_snap = (tail_snap + 1) & RING_MASK;
        process_byte(byte);
    }

    /* 第 4 步：更新 tail（仅在循环结束后）*/
    __DSB();
    rx_tail = tail_snap;
}

/* ===== 重构前：裸指针算术（坏味道：重复逻辑、信息泄露）===== */

/* ISR 中——裸指针算术 */
void DMA_USART2_RX_Callback(void) {
    __DSB();
    static uint16_t prev_h = 0;
    uint16_t new_h = (rx_head + 1) & RING_MASK;
    if ((new_h - prev_h) & RING_MASK > RING_SIZE / 2) {
        overflow_count++;
    }
    prev_h = new_h;
    __DSB();
    rx_head = new_h;
}

/* 任务中——同样的裸指针算术重复一遍 */
void Task_ProcessRX(void) {
    uint16_t avail;
    if (rx_head >= rx_tail) {
        avail = rx_head - rx_tail;
    } else {
        avail = RING_SIZE - rx_tail + rx_head;
    }
    for (uint16_t i = 0; i < avail; i++) {
        uint8_t b = rx_buffer[rx_tail];
        rx_tail = (rx_tail + 1) & RING_MASK;
        parse_byte(b);
    }
}

/* ===== 重构后：ADT 封装（改进：信息隐藏、可复用）===== */

typedef struct {
    volatile uint16_t head;
    volatile uint16_t tail;
    uint16_t size;
    uint16_t mask;
    uint8_t overflow;
    uint8_t data[];
} ringbuf_t;

/* ISR 中——只需一行 */
void DMA_USART2_RX_Callback(void) {
    __DSB();
    ringbuf_push(&usart2_rx_rb, dummy_byte);
}

/* 任务中——只需一行 */
void Task_ProcessRX(void) {
    uint8_t byte;
    while (ringbuf_pop(&usart2_rx_rb, &byte)) {
        parse_byte(byte);
    }
    if (usart2_rx_rb.overflow) {
        usart2_rx_rb.overflow = 0;
        log_overflow();
    }
}
